import sys

class Solution:
    def largestIsland(self, grid: list[list[int]]) -> int:
        n = len(grid)
        m = len(grid[0])
        directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
        island_ids = {}
        island_id = 2
        island_sizes = {}
        max_island_size = 0

        def dfs(r, c, island_id):
            if 0 <= r < n and 0 <= c < m and grid[r][c] == 1:
                grid[r][c] = island_id
                size = 1
                for dr, dc in directions:
                    size += dfs(r + dr, c + dc, island_id)
                return size
            return 0

        for r in range(n):
            for c in range(m):
                if grid[r][c] == 1:
                    island_sizes[island_id] = dfs(r, c, island_id)
                    max_island_size = max(max_island_size, island_sizes[island_id])
                    island_ids[(r, c)] = island_id
                    island_id += 1

        max_area = max_island_size
        for r in range(n):
            for c in range(m):
                if grid[r][c] == 0:
                    adjacent_islands = set()
                    for dr, dc in directions:
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < n and 0 <= nc < m and grid[nr][nc] > 1:
                            adjacent_islands.add(grid[nr][nc])
                    area = 1
                    for island in adjacent_islands:
                        area += island_sizes[island]
                    max_area = max(max_area, area)
        return max_area

if __name__ == '__main__':
