#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int largestIsland(vector<vector<int>>& grid) {
        int n = grid.size();
        int m = grid[0].size();
        vector<pair<int, int>> directions = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};
        unordered_map<int, int> island_sizes;
        int island_id = 2;
        int max_island_size = 0;

        function<int(int, int, int)> dfs = [&](int r, int c, int island_id) {
            if (r >= 0 && r < n && c >= 0 && c < m && grid[r][c] == 1) {
                grid[r][c] = island_id;
                int size = 1;
                for (auto _tmp_pair_0 : directions) { auto dr = _tmp_pair_0.first; auto dc = _tmp_pair_0.second;
                    size += dfs(r + dr, c + dc, island_id);
                }
                return size;
            }
            return 0;
        };

        for (int r = 0; r < n; r++) {
            for (int c = 0; c < m; c++) {
                if (grid[r][c] == 1) {
                    island_sizes[island_id] = dfs(r, c, island_id);
                    max_island_size = max(max_island_size, island_sizes[island_id]);
                    island_id++;
                }
            }
        }

        int max_area = max_island_size;
        for (int r = 0; r < n; r++) {
            for (int c = 0; c < m; c++) {
                if (grid[r][c] == 0) {
                    unordered_set<int> adjacent_islands;
                    for (auto _tmp_pair_1 : directions) { auto dr = _tmp_pair_1.first; auto dc = _tmp_pair_1.second;
                        int nr = r + dr, nc = c + dc;
                        if (nr >= 0 && nr < n && nc >= 0 && nc < m && grid[nr][nc] > 1) {
                            adjacent_islands.insert(grid[nr][nc]);
                        }
                    }
                    int area = 1;
                    for (int island : adjacent_islands) {
                        area += island_sizes[island];
                    }
                    max_area = max(max_area, area);
                }
            }
        }
        return max_area;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, m;
    if (!(cin >> n >> m)) return 0;
    vector<vector<int>> grid(n, vector<int>(m));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            cin >> grid[i][j];
        }
    }
    Solution sol;
    int ans = sol.largestIsland(grid);
    cout << ans << '\n';
    return 0;
}
